import { ChatFlow } from 'flowise';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const chatflow = await ChatFlow.loadChatflowByID('voice-agent-flow');

chatflow.callbacks = {
  onLLMOutput: async (output: any) => {
    await vex.verify({
      sessionId: 'voice-session-' + Date.now(),
      input: output.input,
      output: output.text,
      checks: ['appropriateness', 'safety'],
      latencyBudget: 200
    });
  },
  onToolStart: async (tool: any) => {
    const start = Date.now();
    tool.metadata.vexStart = start;
  },
  onToolEnd: async (tool: any) => {
    await vex.verify({
      sessionId: tool.metadata.sessionId,
      latency: Date.now() - tool.metadata.vexStart,
      check: 'latency_budget',
      threshold: 150
    });
  }
};

// voice-agent-server.ts
const WebSocket = require('ws');
const { Vex } = require('@vex_dev/sdk');

const wss = new WebSocket.Server({ port: 8080 });
const vex = new Vex({ projectId: 'voice-project' });

wss.on('connection', async (ws) => {
  let sessionId = `voice-${Date.now()}`;
  let conversationHistory = [];

  ws.on('message', async (audioBuffer) => {
    try {
      // 1. STT
      const transcript = await deepgram.transcribe(audioBuffer);

      // Vex safety check on raw transcript
      const sttCheck = await vex.verify({
        sessionId,
        stage: 'stt',
        input: audioBuffer,
        output: transcript,
        checks: ['safety_filter']
      });

      if (!sttCheck.pass) {
        ws.send(await elevenLabs.synthesize('I cannot process that request.'));
        return;
      }

      // 2. Flowise reasoning
      conversationHistory.push(transcript);
      const response = await chatflow.chat({
        question: transcript,
        history: conversationHistory.slice(-10),
        sessionId
      });

      // Vex final verification
      const finalCheck = await vex.verify({
        sessionId,
        input: transcript,
        output: response,
        checks: ['coherence', 'appropriateness'],
        latencyBudget: 500
      });

      if (finalCheck.pass) {
        const audio = await elevenLabs.synthesize(response);
        ws.send(audio);
        conversationHistory.push(response);
      }
    } catch (error) {
      await vex.captureError({ sessionId, error });
      ws.send(await elevenLabs.synthesize('Sorry, something went wrong.'));
    }
  });
});

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'voice-agent' });

class VoicePipeline {
  async processAudio(audioBuffer: Buffer, sessionId: string): Promise<Buffer> {
    const stages = ['stt', 'llm', 'rag', 'tts'];
    const budgets = { stt: 100, llm: 200, rag: 100, tts: 100 };
    let totalLatency = 0;

    for (const stage of stages) {
      const stageStart = Date.now();

      let stageOutput;
      switch (stage) {
        case 'stt':
          stageOutput = await deepgram.transcribe(audioBuffer);
          break;
        case 'llm':
          stageOutput = await this.flowise.chat(stageOutput);
          break;
        // ... other stages
      }

      const stageLatency = Date.now() - stageStart;
      totalLatency += stageLatency;

      // Vex budget check
      const budgetCheck = await vex.verify({
        sessionId,
        check: 'latency_budget',
        stage,
        latency: stageLatency,
        threshold: budgets[stage],
        cumulative: totalLatency,
        maxTotal: 500
      });

      if (!budgetCheck.pass) {
        throw new Error(`Stage ${stage} exceeded budget: ${stageLatency}ms`);
      }
    }

    return stageOutput;
  }
}

const COHERENCE_CHECK = {
  prevMessages: 5,
  topicDriftThreshold: 0.7,
  personaConsistency: true
};

async function verifyAgentHandoff(sessionId: string, handoffData: any) {
  const history = await vex.getSessionHistory(sessionId, { limit: 10 });
  const currentIntent = await llm.extractIntent(handoffData.input);

  // Check topic continuity
  const topicDrift = await vex.verify({
    sessionId,
    check: 'conversation_coherence',
    context: {
      history: history.slice(-COHERENCE_CHECK.prevMessages),
      currentIntent,
      prevIntent: history[history.length-1]?.intent
    },
    threshold: COHERENCE_CHECK.topicDriftThreshold
  });

  if (!topicDrift.pass) {
    return {
      pass: false,
      fallback: "Let me make sure I understand. You were talking about " + 
                history[history.length-1]?.topic + ". Is that still right?"
    };
  }

  // Verify no context loss in handoff
  const contextCheck = await vex.verify({
    sessionId,
    check: 'context_preservation',
    input: handoffData.input,
    agentState: handoffData.agentState,
    expectedKeys: ['user_profile', 'conversation_goal']
  });

  return { pass: contextCheck.pass, data: handoffData };
}

