// vex.config.ts
import { Vex } from '@vex_dev/sdk';

export const vex = new Vex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
  riskProfile: 'high',
  defaultChecks: [
    'response_appropriateness',
    'latency_budget',
    'conversation_coherence',
    'safety_filtering'
  ],
  voiceConfig: {
    maxLatency: 500,
    sttSafety: true,
    ttsFallback: true
  }
});

// Add to Flowise STT node callback
chatflow.nodes.stt.callbacks = {
  async onPartialTranscript(transcript: string, sessionId: string) {
    const safetyCheck = await vex.verify({
      sessionId,
      stage: 'stt_partial',
      input: transcript,
      checks: ['safety_filter'],
      voiceContext: true
    });

    if (!safetyCheck.pass) {
      throw new Error('STT safety violation - transcript blocked');
    }
  }
};

async function guardedVoiceResponse(
  audioInput: Buffer, 
  sessionId: string
): Promise<Buffer> {
  const pipelineStart = Date.now();

  const result = await vex.guard({
    sessionId,
    operation: async () => {
      const transcript = await stt(audioInput);
      const reasoning = await chatflow.chat(transcript);
      const speech = await tts(reasoning);
      return speech;
    },
    requirements: {
      latency: { max: 500 },
      safety: 'strict',
      coherence: { window: 10 },
      relevance: { threshold: 0.8 }
    }
  });

  if (!result.pass) {
    console.warn('Voice pipeline blocked:', result.issues);
    return tts('I apologize, but I cannot process that right now.');
  }

  return result.output;
}
